import React, { useEffect, useState } from 'react';
import { useLocation, useNavigate, useParams } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import api from '../utils/api';
import { formatBeijingTimeShort } from '../utils/time';

interface LogItem {
  id: number;
  change_type: string;
  source: string;
  quantity_change: number;
  quantity_before: number | null;
  quantity_after: number | null;
  order_id?: number | null;
  remark?: string | null;
  created_at: string;
}

interface RouteState {
  code?: string;
}

const changeTypeLabel = (type: string) => {
  switch (type) {
    case 'manual_increase':
      return '用户增加';
    case 'manual_decrease':
      return '用户减少';
    case 'order_received_increase':
      return '签收增加';
    case 'order_return_decrease':
      return '退货减少';
    default:
      return type;
  }
};

const InventoryLogs: React.FC = () => {
  const navigate = useNavigate();
  const { productId } = useParams<{ productId: string }>();
  const location = useLocation();
  const state = location.state as RouteState | null;

  const [logs, setLogs] = useState<LogItem[]>([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (productId) {
      loadLogs(productId);
    }
  }, [productId]);

  const loadLogs = async (id: string) => {
    try {
      setLoading(true);
      const res = await api.get<LogItem[]>('/inventory/logs', {
        params: { productId: id },
      });
      setLogs(res.data);
    } catch (error) {
      console.error('加载库存变动记录失败', error);
      alert('加载库存变动记录失败');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      <div className="mb-4">
        <button
          onClick={() => navigate('/inventory')}
          className="flex items-center text-gray-600 hover:text-gray-900 mb-2"
        >
          <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path
              strokeLinecap="round"
              strokeLinejoin="round"
              strokeWidth={2}
              d="M10 19l-7-7m0 0l7-7m-7 7h18"
            />
          </svg>
          返回库存管理
        </button>
        <h1 className="text-2xl font-bold text-gray-900">库存变动记录</h1>
        {state?.code && (
          <p className="text-sm text-gray-500 mt-1">产品代码：{state.code}</p>
        )}
      </div>
      <div className="bg-white rounded-lg shadow p-6">
          {loading ? (
            <div className="text-center py-8 text-gray-500">加载中...</div>
          ) : logs.length === 0 ? (
            <div className="text-center py-8 text-gray-500">暂无库存变动记录</div>
          ) : (
            <div className="overflow-x-auto">
              <table className="min-w-full divide-y divide-gray-200">
                <thead className="bg-gray-50">
                  <tr>
                    <th className="px-4 py-2 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      时间
                    </th>
                    <th className="px-4 py-2 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      类型
                    </th>
                    <th className="px-4 py-2 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      变动数量
                    </th>
                    <th className="px-4 py-2 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      变动前
                    </th>
                    <th className="px-4 py-2 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      变动后
                    </th>
                    <th className="px-4 py-2 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      来源
                    </th>
                    <th className="px-4 py-2 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      备注
                    </th>
                  </tr>
                </thead>
                <tbody className="bg-white divide-y divide-gray-200">
                  {logs.map((log) => (
                    <tr key={log.id}>
                      <td className="px-4 py-2 whitespace-nowrap text-sm text-gray-500">
                        {formatBeijingTimeShort(log.created_at)}
                      </td>
                      <td className="px-4 py-2 whitespace-nowrap text-sm text-gray-700">
                        {changeTypeLabel(log.change_type)}
                      </td>
                      <td className="px-4 py-2 whitespace-nowrap text-sm">
                        <span
                          className={`font-semibold ${
                            log.quantity_change > 0 ? 'text-green-600' : 'text-red-600'
                          }`}
                        >
                          {log.quantity_change > 0 ? '+' : ''}
                          {log.quantity_change}
                        </span>
                      </td>
                      <td className="px-4 py-2 whitespace-nowrap text-sm text-gray-700">
                        {log.quantity_before ?? '-'}
                      </td>
                      <td className="px-4 py-2 whitespace-nowrap text-sm text-gray-700">
                        {log.quantity_after ?? '-'}
                      </td>
                      <td className="px-4 py-2 whitespace-nowrap text-sm text-gray-500">
                        {log.source === 'order' ? '订单' : '手动'}
                        {log.order_id ? ` #${log.order_id}` : ''}
                      </td>
                      <td className="px-4 py-2 whitespace-nowrap text-sm text-gray-500">
                        {log.remark || '-'}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
      </div>
    </div>
  );
};

export default InventoryLogs;


