import React from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const Dashboard: React.FC = () => {
  const navigate = useNavigate();
  const { user, logout, isAdmin } = useAuth();

  const modules = [
    {
      id: 'inventory',
      title: '库存管理',
      description: '管理拼豆库存，查看统计信息，更新库存数量',
      icon: (
        <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4" />
        </svg>
      ),
      color: 'bg-blue-500',
      hoverColor: 'bg-blue-600',
      path: '/inventory',
    },
    {
      id: 'drawings',
      title: '图纸档案管理',
      description: '管理拼豆图纸档案，查看和编辑图纸信息',
      icon: (
        <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
        </svg>
      ),
      color: 'bg-green-500',
      hoverColor: 'bg-green-600',
      path: '/drawings',
    },
    // settings module intentionally hidden from dashboard
    // consumption module removed per requirements
    {
      id: 'orders',
      title: '订单管理 / 在途库存',
      description: '录入采购订单，管理在途/已签收/已退货库存',
      icon: (
        <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path
            strokeLinecap="round"
            strokeLinejoin="round"
            strokeWidth={2}
            d="M3 7h18M3 7l2 12h14l2-12M5 7l1-3h12l1 3M10 11h4m-4 4h2"
          />
        </svg>
      ),
      color: 'bg-orange-500',
      hoverColor: 'bg-orange-600',
      path: '/orders',
    },
    {
      id: 'pixelate',
      title: '像素化查看',
      description: '将图片像素化并映射为物料颜色，交互查看与统计',
      icon: (
        <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4h6v6H4zM14 4h6v6h-6zM4 14h6v6H4zM14 14h6v6h-6z" />
        </svg>
      ),
      color: 'bg-purple-500',
      hoverColor: 'bg-purple-600',
      path: '/pixelate',
    },
  ];

  return (
    <div className="min-h-screen bg-gradient-to-br from-gray-50 to-gray-100">
      {/* 主内容区域 */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
        <div className="text-center mb-12">
          <h2 className="text-4xl font-bold text-gray-900 mb-4">选择功能模块</h2>
          <p className="text-lg text-gray-600">请选择要使用的功能模块</p>
        </div>

        {/* 模块卡片网格 */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {modules.map((module) => (
            <div
              key={module.id}
              onClick={() => navigate(module.path)}
              className="bg-white rounded-xl shadow-lg hover:shadow-xl transition-all duration-300 cursor-pointer transform hover:-translate-y-2"
            >
              <div className={`${module.color} rounded-t-xl p-8 flex items-center justify-center text-white`}>
                {module.icon}
              </div>
              <div className="p-6">
                <h3 className="text-2xl font-bold text-gray-900 mb-3">{module.title}</h3>
                <p className="text-gray-600 leading-relaxed">{module.description}</p>
                <div className="mt-6">
                  <button
                    className={`w-full ${module.color} ${module.hoverColor} text-white py-3 px-6 rounded-lg font-medium transition-colors`}
                  >
                    进入模块
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
